async function _mapSection(d3,mapImage,regions,labelsImage,characters,icons,splashArts)
{
  const mapW = 9309, mapH = 7370;

  const svg = d3.create("svg")
  .attr("viewBox", `0 0 ${mapW} ${mapH}`)
  .attr("width", "100%")
  .attr("height", "100%")
  .style("display", "block");

  const g = svg.append("g");

  g.append("image")
    .attr("href", await mapImage)
    .attr("width", mapW)
    .attr("height", mapH);

  // draw all region outlines
  const regionPaths = {};
  regions.forEach(r => {
    const p = g.append("path")
      .attr("d", r.path)
      .attr("transform", `translate(${r.x}, ${r.y})`)
      .attr("fill", r.fill)
      .attr("fill-opacity", 0.5)
      .attr("stroke", "white")
      .attr("stroke-width", 10)
      .style("cursor", "pointer")
      .on("mouseover", function() {
        d3.select(this).attr("fill-opacity", 0.75).attr("stroke-width", 20);
      })
      .on("mouseout", function() {
        d3.select(this).attr("fill-opacity", 0.5).attr("stroke-width", 10);
      })
      .on("click", () => clickRegion(r, p));
    regionPaths[r.name] = p;
  });

  const labels = g.append("image")
    .attr("href", await labelsImage)
    .attr("width", mapW)
    .attr("height", mapH)
    .style("pointer-events", "none");

  // character icons
  g.selectAll(".char-icon")
    .data(characters)
    .join("image")
    .attr("href", d => icons[d.Character])
    .attr("x", d => d.realX)
    .attr("y", d => d.realY)
    .attr("width", 165)
    .attr("height", 205)
    .attr("opacity", 0)
    .attr("data-region", d => d.Region)
    .classed("char-icon", true)
    .style("cursor", "pointer")
    .on("click", function(event, d) {
  if (d3.select(this).attr("opacity") === "0") return;
  event.stopPropagation();
  window.openCharacterCard(d);
});

const zoom = d3.zoom()
.scaleExtent([Math.min(window.innerWidth / mapW, window.innerHeight / mapH), 8])
.on("zoom", e => g.attr("transform", e.transform));

  svg.call(zoom);

  // fit map to screen on load
  const fitScale = Math.min(window.innerWidth / mapW, window.innerHeight / mapH) * 1.0;
  const fitX = (window.innerWidth - mapW * fitScale) / 2;
  const fitY = (window.innerHeight - mapH * fitScale) / 2;
  svg.call(zoom.transform, d3.zoomIdentity.translate(fitX, fitY).scale(fitScale));

  function clickRegion(r, path) {
    const scale = Math.max(1, Math.min(8, 1.2 / Math.max(r.w / mapW, r.h / mapH)));
    const cx = r.x + r.w / 2;
    const cy = r.y + r.h / 2;
    const offsetX = {
      "Mondstadt": 200,
      "Liyue": 200,
      "Inazuma": 200,
      "Sumeru": 800,
      "Fontaine": 200,
      "Natlan": 800,
      "Nod Krai": 200
    }[r.name] ?? 200;
    const offsetY = {
      "Mondstadt": 600,
      "Liyue": 500,
      "Inazuma": -900,
      "Sumeru": 200,
      "Fontaine": -600,
      "Natlan": 900,
      "Nod Krai": 600
    }[r.name] ?? 600;
    const translate = [mapW / 2 - scale * cx - offsetX, mapH / 2 - scale * cy - offsetY];

    g.selectAll(".char-icon")
      .transition().duration(750)
      .attr("opacity", function() {
        return d3.select(this).attr("data-region") === r.name ? 1 : 0;
      });

    labels.transition().duration(750).attr("opacity", 0);
    Object.values(regionPaths).forEach(p => p.transition().duration(750).attr("opacity", 0));

    svg.transition().duration(750).call(zoom.transform,
      d3.zoomIdentity.translate(translate[0], translate[1]).scale(scale));
  }

  svg.on("click", function(event) {
    if (event.target === svg.node() || event.target.tagName === "image") {
      g.selectAll(".char-icon").transition().duration(750).attr("opacity", 0);
      labels.transition().duration(750).attr("opacity", 1);
      Object.values(regionPaths).forEach(p => p.transition().duration(750).attr("opacity", 1));
      const _fitScale = Math.min(window.innerWidth / mapW, window.innerHeight / mapH) * 1.0;
      const _fitX = (window.innerWidth - mapW * _fitScale) / 2;
      const _fitY = (window.innerHeight - mapH * _fitScale) / 2;
      svg.transition().duration(750).call(zoom.transform, d3.zoomIdentity.translate(_fitX, _fitY).scale(_fitScale));
    }
  });

  // ── WRAPPER ──
  const wrapper = document.createElement("div");
wrapper.id = "map-section";
wrapper.style.cssText = "position:relative; overflow:hidden; width:100vw; height:100vh;";
  wrapper.appendChild(svg.node());

  const mapBackBtn = document.createElement("div");
mapBackBtn.style.cssText = `position:absolute;top:16px;right:16px;cursor:pointer;transition:transform 0.2s;z-index:10;`;
mapBackBtn.innerHTML = `<svg width="48" height="48" viewBox="0 0 77 77" fill="none" xmlns="http://www.w3.org/2000/svg"><circle cx="38.0107" cy="38.0107" r="31.0107" fill="#EBE7D8"/><circle cx="38.0107" cy="38.0107" r="34.5107" stroke="#EBE7D8" stroke-opacity="0.5" stroke-width="7"/><path d="M37.1631 28.0425C44.8237 27.1751 58.0352 31.0762 58.0352 42.3267C58.0351 57.1389 41.9149 60.2895 33.8545 60.0132C39.8421 59.5526 51.8169 56.6969 51.8174 48.9595C51.8174 41.7854 42.7114 40.4718 37.1631 40.7222V50.1372C35.0976 45.255 23.1413 37.0092 17.9863 34.8784C23.1413 32.7476 35.0977 24.5018 37.1631 19.6196V28.0425Z" fill="#3C4255"/></svg>`;
mapBackBtn.addEventListener("mouseenter", () => mapBackBtn.style.transform = "scale(1.08)");
mapBackBtn.addEventListener("mouseleave", () => mapBackBtn.style.transform = "scale(1)");
mapBackBtn.addEventListener("click", () => {
  window.showScreen('landing');
});
wrapper.appendChild(mapBackBtn);

  // ── CARD OVERLAY (appended to wrapper directly) ──
  const overlayEl = document.createElement("div");
  overlayEl.id = "card-overlay";
  overlayEl.style.cssText = "position:absolute;inset:0;background:rgba(0,0,0,0);z-index:50;display:none;transition:background 0.4s ease;";
  overlayEl.addEventListener("click", () => window.closeCard());
  wrapper.appendChild(overlayEl);

  const cardEl = document.createElement("div");
  cardEl.id = "character-card";
  cardEl.style.cssText = "position:absolute;top:0;right:-400px;width:400px;height:100%;max-height:100%;overflow-y:auto;overflow-x:hidden;background:#D8D6CA;z-index:51;display:flex;flex-direction:column;transition:right 0.4s ease;font-family:'GenshinFont',sans-serif;";
  cardEl.addEventListener("click", e => e.stopPropagation());
  wrapper.appendChild(cardEl);

  // ── CARD FUNCTIONS ──
  window.openCharacterCard = function(d) {
    cardEl.innerHTML = "";

    // top bar
    const topBar = document.createElement("div");
    topBar.style.cssText = "background:#3D4454;padding:20px 24px;display:flex;justify-content:space-between;align-items:center;flex-shrink:0;";
    const nameSpan = document.createElement("span");
    nameSpan.style.cssText = "color:#CBB993;font-size:28px;";
    nameSpan.textContent = d.Character;
    const closeSpan = document.createElement("span");
    closeSpan.style.cssText = "color:#EEE4DA;font-size:24px;cursor:pointer;line-height:1;";
    closeSpan.textContent = "✕";
    closeSpan.addEventListener("click", () => window.closeCard());
    topBar.appendChild(nameSpan);
    topBar.appendChild(closeSpan);
    cardEl.appendChild(topBar);

    // splash art
    if (splashArts[d.Character]) {
  const img = document.createElement("img");
  img.src = splashArts[d.Character];
  img.style.cssText = "width:100%;height:180px;object-fit:contain;object-position:center;flex-shrink:0;background:#D8D6CA;padding:16px 0;box-sizing:border-box;";
  cardEl.appendChild(img);
    }

    // attributes
    const attrs = document.createElement("div");
    attrs.style.cssText = "padding:20px 24px;color:#4E525C;flex-shrink:0;";
    const attrsTitle = document.createElement("div");
    attrsTitle.style.cssText = "font-size:20px;font-weight:bold;margin-bottom:16px;";
    attrsTitle.textContent = "Attributes";
    attrs.appendChild(attrsTitle);
    [
      { label: "Rarity", value: "⭐".repeat(+d.Rarity) },
      { label: "Element", value: d.Element },
      { label: "Weapon Type", value: d.WeaponType },
      { label: "Model Type", value: d.ModelType }
    ].forEach(row => {
      const r = document.createElement("div");
      r.style.cssText = "display:flex;justify-content:space-between;align-items:center;padding:8px 0;border-bottom:1px solid rgba(78,82,92,0.15);";
      r.innerHTML = `<span style="font-size:15px;">${row.label}</span><span style="font-size:15px;">${row.value}</span>`;
      attrs.appendChild(r);
    });
    cardEl.appendChild(attrs);

    // constellation
    const constSection = document.createElement("div");
    constSection.style.cssText = "padding:20px 24px;color:#4E525C;flex-shrink:0;";
    const constTitle = document.createElement("div");
    constTitle.style.cssText = "font-size:20px;font-weight:bold;margin-bottom:16px;";
    constTitle.textContent = "Constellation Own Rate";
    constSection.appendChild(constTitle);
    const consts = ["C0","C1","C2","C3","C4","C5","C6"];
    const maxVal = Math.max(...consts.map(c => +d[`${c}OwnRate`] || 0));
    consts.forEach(c => {
      const val = +d[`${c}OwnRate`] || 0;
      const row = document.createElement("div");
      row.style.cssText = "display:flex;align-items:center;gap:10px;margin-bottom:10px;";
      const label = document.createElement("span");
      label.style.cssText = "font-size:13px;width:24px;flex-shrink:0;";
      label.textContent = c;
      const barBg = document.createElement("div");
      barBg.style.cssText = "flex:1;background:rgba(78,82,92,0.15);border-radius:4px;height:12px;overflow:hidden;";
      const barFill = document.createElement("div");
      barFill.style.cssText = `width:${val}%;height:100%;background:#F6F2B1;border-radius:4px;transition:width 0.6s ease;`;
      barBg.appendChild(barFill);
      const pct = document.createElement("span");
      pct.style.cssText = "font-size:13px;width:42px;text-align:right;flex-shrink:0;";
      pct.textContent = `${val}%`;
      row.appendChild(label); row.appendChild(barBg); row.appendChild(pct);
      constSection.appendChild(row);
    });
    cardEl.appendChild(constSection);

    // pull count section
// pull count section
const pullSection = document.createElement("div");
pullSection.style.cssText = "padding:20px 24px;color:#4E525C;flex-shrink:0;";

const pullHeader = document.createElement("div");
pullHeader.style.cssText = "display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;";
const pullTitle = document.createElement("span");
pullTitle.style.cssText = "font-size:17px;font-weight:bold;";
pullTitle.textContent = "Total Pull Count (v6.5)";
const pullTotal = document.createElement("span");
pullTotal.style.cssText = "font-size:17px;font-weight:bold;";
pullTotal.textContent = parseInt(d.PullRate || 0).toLocaleString();
pullHeader.appendChild(pullTitle);
pullHeader.appendChild(pullTotal);
pullSection.appendChild(pullHeader);

const bannerLabels = ["Debut Banner","1st Rerun","2nd Rerun","3rd Rerun","4th Rerun","5th Rerun","6th Rerun"];
const bannerKeys = ["1stBanner","2ndBanner","3rdBanner","4thBanner","5thBanner","6thBanner","7thBanner"];
// dark to light gradient — debut is darkest (most pulls), reruns get lighter
// text color pairs: dark bg = light text, light bg = dark text
const bannerColors = [
  { bg: "#7A5100", text: "#FFE8BC" }, // Debut — darkest brown
  { bg: "#B07820", text: "#FFF3D6" }, // 1st Rerun
  { bg: "#CE9F3A", text: "#3D2A00" }, // 2nd Rerun
  { bg: "#DEB96A", text: "#3D2A00" }, // 3rd Rerun
  { bg: "#EDD49A", text: "#4E3800" }, // 4th Rerun
  { bg: "#F5E6C0", text: "#4E3800" }, // 5th Rerun
  { bg: "#FAF2DC", text: "#5C4510" }, // 6th Rerun — lightest
];

const activeBanners = bannerKeys
  .map((key, i) => ({ label: bannerLabels[i], val: parseInt(d[key] || 0), color: bannerColors[i], idx: i }))
  .filter(b => b.val > 0);

const total = parseInt(d.PullRate || 0);

// stacked bar
if (activeBanners.length > 0 && total > 0) {
  const barWrap = document.createElement("div");
  barWrap.style.cssText = "display:flex;width:100%;height:24px;border-radius:6px;overflow:hidden;margin-bottom:14px;position:relative;";

  activeBanners.forEach((b, i) => {
    const pct = (b.val / total) * 100;
    const seg = document.createElement("div");
    seg.style.cssText = `width:${pct}%;height:100%;background:${b.color.bg};position:relative;display:flex;align-items:center;justify-content:center;overflow:hidden;flex-shrink:0;`;

    // label inside bar — only show if segment is wide enough
    const segLabel = document.createElement("span");
    segLabel.style.cssText = `font-size:9px;color:${b.color.text};white-space:nowrap;padding:0 4px;font-family:'GenshinFont',sans-serif;pointer-events:none;`;
    segLabel.textContent = `${i === 0 ? "Debut" : i + "R"}: ${pct.toFixed(1)}%`;
    seg.appendChild(segLabel);

    // hide label if segment too narrow — check after append
    const minWidthForLabel = 48;
    requestAnimationFrame(() => {
      if (seg.offsetWidth < minWidthForLabel) segLabel.style.display = "none";
    });

    barWrap.appendChild(seg);
  });

  pullSection.appendChild(barWrap);
}

// banner rows
activeBanners.forEach(b => {
  const pct = total > 0 ? ((b.val / total) * 100).toFixed(1) : "0.0";
  const row = document.createElement("div");
  row.style.cssText = "display:flex;justify-content:space-between;align-items:center;padding:4px 0;border-bottom:1px solid rgba(78,82,92,0.1);gap:8px;";
  const dot = document.createElement("div");
  dot.style.cssText = `width:8px;height:8px;border-radius:2px;background:${b.color.bg};flex-shrink:0;border:1px solid rgba(78,82,92,0.2);`;
  const lbl = document.createElement("span");
  lbl.style.cssText = "font-size:12px;color:rgba(78,82,92,0.75);flex:1;";
  lbl.textContent = b.label;
  const amt = document.createElement("span");
  amt.style.cssText = "font-size:12px;color:rgba(78,82,92,0.75);text-align:right;";
  amt.textContent = `${b.val.toLocaleString()} (${pct}% of total)`;
  row.appendChild(dot); row.appendChild(lbl); row.appendChild(amt);
  pullSection.appendChild(row);
});

cardEl.appendChild(pullSection);

    // show
    overlayEl.style.display = "block";
    setTimeout(() => {
      overlayEl.style.background = "rgba(0,0,0,0.5)";
      cardEl.style.right = "0";
    }, 10);
  };

  window.closeCard = function() {
    overlayEl.style.background = "rgba(0,0,0,0)";
    cardEl.style.right = "-400px";
    setTimeout(() => { overlayEl.style.display = "none"; }, 400);
  };

  return wrapper;
}


