    const {w, h} = window._getChartDims ? window._getChartDims() : {w:560, h:400};
const W=w, H=Math.floor(h*0.85), M={top:16,right:170,bottom:46,left:56};
    const iW=W-M.left-M.right, iH=H-M.top-M.bottom;
